query:
SELECT p.id, p.name, p.price FROM products WHERE id IN (300057, 300002);

SELECT cg.id as groupId, cg.name as groupName, cg.productId, ci.id as itemId, ci.name as itemName, ci.price as itemPrice 
FROM complement_groups cg 
JOIN complement_items ci ON ci.groupId = cg.id 
WHERE cg.productId IN (300057, 300002) 
ORDER BY cg.productId, cg.id, ci.id;

